import Typography from '@mui/material/Typography';
import { CardHeader } from '@mui/material';


interface ProductCardProps{
    image: string,
    header: string,
    descirption: string,
    button1Url: string,
    button2Url:string
}

export const ProductCard: React.FC <{}> = () =>{
    return (
        <Card sx={{maxWidth:345}}>
            <CardMedia
            component="img"
